1	//! WAM-style compilation: `Clause` stream to `Instr` stream.
2	//!
3	//! Mirrors the `codegen.sno` algorithm for the ancestor subset:
4	//! per-clause VMap assigning each variable slot an X-register on first
5	//! occurrence; all head/body var references reuse that mapping. Multi-
6	//! clause predicates get a `TRY/RETRY/TRUST` dispatcher under
7	//! `pred_entry`. Clause bodies land at `pred_cK_body` labels and the
8	//! query at `query:`. Atom directives are emitted for every interned
9	//! atom (ordered by AtomId), followed by an initial `EXECUTE query`.
10	//!
11	//! Y-register classification plus `ALLOCATE`/`DEALLOCATE` is deferred:
12	//! ancestor.pl under LAM VM semantics (X-registers preserved across
13	//! `CALL`) does not need them. Later steps slot in `GetStruct`,
14	//! `UnifyVar`, `UnifyVal`, `Cut`, `Fail`, and the `B_*` variants.
15	
16	use crate::parse::{
17	    AtomId, AtomTable, Clause, ClauseKind, Term, TermIdx, VarSlot,
18	    MAX_ARGS, MAX_CLAUSES, MAX_CLAUSE_VARS, NAME_CAP,
19	};
20	use crate::port::{BoundedArr, BoundedStr};
21	use thiserror::Error;
22	
23	pub const MAX_INSTR: usize = 2048;
24	pub const LABEL_CAP: usize = 48;
25	
26	pub type LabelId = BoundedStr<LABEL_CAP>;
27	
28	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
29	pub enum Instr {
30	    PutConst { ai: u8, atom: AtomId },
31	    PutVar { ai: u8, xi: u8 },
32	    PutVal { ai: u8, xi: u8 },
33	    PutYVal { ai: u8, yi: u8 },
34	    GetVar { ai: u8, xi: u8 },
35	    GetYVar { ai: u8, yi: u8 },
36	    GetConst { ai: u8, atom: AtomId },
37	    GetStruct { ai: u8, atom: AtomId, arity: u8 },
38	    UnifyVar { xi: u8 },
39	    UnifyVal { xi: u8 },
40	    Allocate { n: u8 },
41	    Deallocate,
42	    Call { label: LabelId },
43	    Execute { label: LabelId },
44	    Proceed,
45	    Try { label: LabelId },
46	    Retry { label: LabelId },
47	    Trust { label: LabelId },
48	    Cut,
49	    Fail,
50	    BWrite { ai: u8 },
51	    BNl,
52	    BIsAdd { dst: u8, a: u8, b: u8 },
53	    BIsSub { dst: u8, a: u8, b: u8 },
54	    BLt { a: u8, b: u8 },
55	    BGt { a: u8, b: u8 },
56	    Halt,
57	    Label(LabelId),
58	    AtomDir { id: AtomId, name: BoundedStr<NAME_CAP> },
59	}
60	
61	#[derive(Debug, Error, Clone, Copy, PartialEq, Eq)]
62	pub enum CompileError {
63	    #[error("instruction stream overflow")]
64	    InstrOverflow,
65	    #[error("label name too long")]
66	    LabelOverflow,
67	    #[error("unknown atom id in clause")]
68	    UnknownAtom,
69	    #[error("clause head is not an atom or functor")]
70	    BadHead,
71	    #[error("goal is not an atom or functor")]
72	    BadGoal,
73	    #[error("no query clause in program")]
74	    NoQuery,
75	    #[error("more than one query clause")]
76	    MultipleQueries,
77	    #[error("subterm index out of range")]
78	    BadSubterm,
79	    #[error("var slot out of range")]
80	    TooManyVars,
81	    #[error("too many X-registers in clause")]
82	    TooManyXRegs,
83	    #[error("query must contain exactly one goal (multi-goal queries deferred)")]
84	    QueryShape,
85	    #[error("repeated head var (GET_VAL) not supported in this subset")]
86	    HeadVarRepeat,
87	    #[error("nested struct in arg position not supported in this subset")]
88	    StructArg,
89	    #[error("integer literal in arg position not supported in this subset")]
90	    IntArg,
91	    #[error("empty body in rule")]
92	    EmptyBody,
93	}
94	
95	const SENTINEL_X: u8 = u8::MAX;
96	
97	struct XMap {
98	    slot_to_x: BoundedArr<u8, MAX_CLAUSE_VARS>,
99	    next_x: u8,
100	}
101	
102	impl XMap {
103	    fn new() -> Self {
104	        let mut slot_to_x: BoundedArr<u8, MAX_CLAUSE_VARS> = BoundedArr::new();
105	        for _ in 0..MAX_CLAUSE_VARS {
106	            slot_to_x.push(SENTINEL_X).expect("xmap prefill within capacity");
107	        }
108	        Self { slot_to_x, next_x: 0 }
109	    }
110	
111	    fn lookup_or_assign(&mut self, slot: VarSlot) -> Result<(u8, bool), CompileError> {
112	        let idx = slot as usize;
113	        if idx >= MAX_CLAUSE_VARS {
114	            return Err(CompileError::TooManyVars);
115	        }
116	        let cur = *self.slot_to_x.get(idx).expect("xmap index in range");
117	        if cur != SENTINEL_X {
118	            return Ok((cur, true));
119	        }
120	        if self.next_x == SENTINEL_X {
121	            return Err(CompileError::TooManyXRegs);
122	        }
123	        let x = self.next_x;
124	        *self.slot_to_x.get_mut(idx).expect("xmap index in range") = x;
125	        self.next_x += 1;
126	        Ok((x, false))
127	    }
128	}
129	
130	pub fn compile(
131	    clauses: &BoundedArr<Clause, MAX_CLAUSES>,
132	    atoms: &AtomTable,
133	) -> Result<BoundedArr<Instr, MAX_INSTR>, CompileError> {
134	    let query_ix = find_query(clauses)?;
135	    let mut out: BoundedArr<Instr, MAX_INSTR> = BoundedArr::new();
136	    emit_atom_dirs(atoms, &mut out)?;
137	    push_i(&mut out, Instr::Execute { label: lbl_query()? })?;
138	    emit_all_predicates(clauses, query_ix, atoms, &mut out)?;
139	    emit_query_clause(
140	        clauses.get(query_ix).expect("query index in range"),
141	        atoms,
142	        &mut out,
143	    )?;
144	    Ok(out)
145	}
146	
147	fn find_query(clauses: &BoundedArr<Clause, MAX_CLAUSES>) -> Result<usize, CompileError> {
148	    let mut found: Option<usize> = None;
149	    for i in 0..clauses.len() {
150	        if clauses.get(i).expect("clause index in range").kind == ClauseKind::Query {
151	            if found.is_some() {
152	                return Err(CompileError::MultipleQueries);
153	            }
154	            found = Some(i);
155	        }
156	    }
157	    found.ok_or(CompileError::NoQuery)
158	}
159	
160	fn push_i(out: &mut BoundedArr<Instr, MAX_INSTR>, i: Instr) -> Result<(), CompileError> {
161	    out.push(i).map_err(|_| CompileError::InstrOverflow)
162	}
163	
164	fn emit_atom_dirs(
165	    atoms: &AtomTable,
166	    out: &mut BoundedArr<Instr, MAX_INSTR>,
167	) -> Result<(), CompileError> {
168	    for id in 0..atoms.len() as AtomId {
169	        let name = *atoms.name(id).ok_or(CompileError::UnknownAtom)?;
170	        push_i(out, Instr::AtomDir { id, name })?;
171	    }
172	    Ok(())
173	}
174	
175	fn emit_all_predicates(
176	    clauses: &BoundedArr<Clause, MAX_CLAUSES>,
177	    query_ix: usize,
178	    atoms: &AtomTable,
179	    out: &mut BoundedArr<Instr, MAX_INSTR>,
180	) -> Result<(), CompileError> {
181	    let mut i = 0;
182	    while i < clauses.len() {
183	        if i == query_ix {
184	            i += 1;
185	            continue;
186	        }
187	        let (end, pid) = scan_group(clauses, i, query_ix)?;
188	        emit_group(clauses, i, end, pid, atoms, out)?;
189	        i = end;
190	    }
191	    Ok(())
192	}
193	
194	fn scan_group(
195	    clauses: &BoundedArr<Clause, MAX_CLAUSES>,
196	    start: usize,
197	    query_ix: usize,
198	) -> Result<(usize, AtomId), CompileError> {
199	    let c0 = clauses.get(start).expect("start in range");
200	    let (fid, ar) = head_pred(&c0.head)?;
201	    let mut end = start + 1;
202	    while end < clauses.len() && end != query_ix {
203	        let c = clauses.get(end).expect("end in range");
204	        let (fid2, ar2) = head_pred(&c.head)?;
205	        if fid2 != fid || ar2 != ar {
206	            break;
207	        }
208	        end += 1;
209	    }
210	    Ok((end, fid))
211	}
212	
213	fn head_pred(head: &Term) -> Result<(AtomId, u8), CompileError> {
214	    match head {
215	        Term::Atom(id) => Ok((*id, 0)),
216	        Term::Struct { functor, args } => Ok((*functor, args.len() as u8)),
217	        _ => Err(CompileError::BadHead),
218	    }
219	}
220	
221	fn emit_group(
222	    clauses: &BoundedArr<Clause, MAX_CLAUSES>,
223	    start: usize,
224	    end: usize,
225	    pid: AtomId,
226	    atoms: &AtomTable,
227	    out: &mut BoundedArr<Instr, MAX_INSTR>,
228	) -> Result<(), CompileError> {
229	    let pname = *atoms.name(pid).ok_or(CompileError::UnknownAtom)?;
230	    let count = end - start;
231	    for k in 0..count {
232	        let clause = clauses.get(start + k).expect("clause in range");
233	        let clause_idx = (k + 1) as u8;
234	        emit_clause_body(clause, &pname, clause_idx, atoms, out)?;
235	    }
236	    emit_dispatcher(&pname, count as u8, out)
237	}
238	
239	fn emit_clause_body(
240	    clause: &Clause,
241	    pname: &BoundedStr<NAME_CAP>,
242	    clause_idx: u8,
243	    atoms: &AtomTable,
244	    out: &mut BoundedArr<Instr, MAX_INSTR>,
245	) -> Result<(), CompileError> {
246	    push_i(out, Instr::Label(lbl_clause_body(pname, clause_idx)?))?;
247	    let mut xm = XMap::new();
248	    emit_head(&clause.head, clause, &mut xm, out)?;
249	    match clause.kind {
250	        ClauseKind::Fact => push_i(out, Instr::Proceed),
251	        ClauseKind::Rule => emit_body(clause, atoms, &mut xm, out),
252	        ClauseKind::Query => Err(CompileError::BadHead),
253	    }
254	}
255	
256	fn emit_head(
257	    head: &Term,
258	    clause: &Clause,
259	    xm: &mut XMap,
260	    out: &mut BoundedArr<Instr, MAX_INSTR>,
261	) -> Result<(), CompileError> {
262	    match head {
263	        Term::Atom(_) => Ok(()),
264	        Term::Struct { args, .. } => emit_head_args(args, clause, xm, out),
265	        _ => Err(CompileError::BadHead),
266	    }
267	}
268	
269	fn emit_head_args(
270	    args: &BoundedArr<TermIdx, MAX_ARGS>,
271	    clause: &Clause,
272	    xm: &mut XMap,
273	    out: &mut BoundedArr<Instr, MAX_INSTR>,
274	) -> Result<(), CompileError> {
275	    for i in 0..args.len() {
276	        let ti = *args.get(i).expect("arg index in range");
277	        let t = *clause.subterm(ti).ok_or(CompileError::BadSubterm)?;
278	        emit_head_arg(i as u8, &t, xm, out)?;
279	    }
280	    Ok(())
281	}
282	
283	fn emit_head_arg(
284	    ai: u8,
285	    arg: &Term,
286	    xm: &mut XMap,
287	    out: &mut BoundedArr<Instr, MAX_INSTR>,
288	) -> Result<(), CompileError> {
289	    match arg {
290	        Term::Atom(id) => push_i(out, Instr::GetConst { ai, atom: *id }),
291	        Term::Var(slot) => {
292	            let (xi, seen) = xm.lookup_or_assign(*slot)?;
293	            if seen {
294	                Err(CompileError::HeadVarRepeat)
295	            } else {
296	                push_i(out, Instr::GetVar { ai, xi })
297	            }
298	        }
299	        Term::Int(_) => Err(CompileError::IntArg),
300	        Term::Struct { .. } => Err(CompileError::StructArg),
301	        Term::Nil => Err(CompileError::StructArg),
302	    }
303	}
304	
305	fn emit_body(
306	    clause: &Clause,
307	    atoms: &AtomTable,
308	    xm: &mut XMap,
309	    out: &mut BoundedArr<Instr, MAX_INSTR>,
310	) -> Result<(), CompileError> {
311	    let n = clause.body.len();
312	    if n == 0 {
313	        return Err(CompileError::EmptyBody);
314	    }
315	    for gi in 0..n {
316	        let goal = *clause.body.get(gi).expect("goal index in range");
317	        let is_last = gi + 1 == n;
318	        emit_goal(&goal, clause, atoms, xm, is_last, out)?;
319	    }
320	    Ok(())
321	}
322	
323	fn emit_goal(
324	    goal: &Term,
325	    clause: &Clause,
326	    atoms: &AtomTable,
327	    xm: &mut XMap,
328	    is_last: bool,
329	    out: &mut BoundedArr<Instr, MAX_INSTR>,
330	) -> Result<(), CompileError> {
331	    let fid = match goal {
332	        Term::Atom(id) => *id,
333	        Term::Struct { functor, args } => {
334	            emit_put_args(args, clause, xm, out)?;
335	            *functor
336	        }
337	        _ => return Err(CompileError::BadGoal),
338	    };
339	    let pname = *atoms.name(fid).ok_or(CompileError::UnknownAtom)?;
340	    let entry = lbl_entry(&pname)?;
341	    let ctrl = if is_last {
342	        Instr::Execute { label: entry }
343	    } else {
344	        Instr::Call { label: entry }
345	    };
346	    push_i(out, ctrl)
347	}
348	
349	fn emit_put_args(
350	    args: &BoundedArr<TermIdx, MAX_ARGS>,
351	    clause: &Clause,
352	    xm: &mut XMap,
353	    out: &mut BoundedArr<Instr, MAX_INSTR>,
354	) -> Result<(), CompileError> {
355	    for i in 0..args.len() {
356	        let ti = *args.get(i).expect("arg index in range");
357	        let t = *clause.subterm(ti).ok_or(CompileError::BadSubterm)?;
358	        emit_put_arg(i as u8, &t, xm, out)?;
359	    }
360	    Ok(())
361	}
362	
363	fn emit_put_arg(
364	    ai: u8,
365	    arg: &Term,
366	    xm: &mut XMap,
367	    out: &mut BoundedArr<Instr, MAX_INSTR>,
368	) -> Result<(), CompileError> {
369	    match arg {
370	        Term::Atom(id) => push_i(out, Instr::PutConst { ai, atom: *id }),
371	        Term::Var(slot) => {
372	            let (xi, seen) = xm.lookup_or_assign(*slot)?;
373	            if seen {
374	                push_i(out, Instr::PutVal { ai, xi })
375	            } else {
376	                push_i(out, Instr::PutVar { ai, xi })
377	            }
378	        }
379	        Term::Int(_) => Err(CompileError::IntArg),
380	        Term::Struct { .. } => Err(CompileError::StructArg),
381	        Term::Nil => Err(CompileError::StructArg),
382	    }
383	}
384	
385	fn emit_dispatcher(
386	    pname: &BoundedStr<NAME_CAP>,
387	    clause_count: u8,
388	    out: &mut BoundedArr<Instr, MAX_INSTR>,
389	) -> Result<(), CompileError> {
390	    push_i(out, Instr::Label(lbl_entry(pname)?))?;
391	    if clause_count == 1 {
392	        return push_i(out, Instr::Execute { label: lbl_clause_body(pname, 1)? });
393	    }
394	    push_i(out, Instr::Try { label: lbl_clause(pname, 2)? })?;
395	    push_i(out, Instr::Execute { label: lbl_clause_body(pname, 1)? })?;
396	    let mut k = 2u8;
397	    while k <= clause_count {
398	        push_i(out, Instr::Label(lbl_clause(pname, k)?))?;
399	        let cbody = lbl_clause_body(pname, k)?;
400	        if k == clause_count {
401	            push_i(out, Instr::Trust { label: cbody })?;
402	        } else {
403	            push_i(out, Instr::Retry { label: lbl_clause(pname, k + 1)? })?;
404	        }
405	        push_i(out, Instr::Execute { label: cbody })?;
406	        k += 1;
407	    }
408	    Ok(())
409	}
410	
411	fn emit_query_clause(
412	    clause: &Clause,
413	    atoms: &AtomTable,
414	    out: &mut BoundedArr<Instr, MAX_INSTR>,
415	) -> Result<(), CompileError> {
416	    push_i(out, Instr::Label(lbl_query()?))?;
417	    if clause.body.len() != 1 {
418	        return Err(CompileError::QueryShape);
419	    }
420	    let goal = *clause.body.get(0).expect("single-goal query");
421	    let mut xm = XMap::new();
422	    let fid = match goal {
423	        Term::Atom(id) => id,
424	        Term::Struct { functor, args } => {
425	            emit_put_args(&args, clause, &mut xm, out)?;
426	            functor
427	        }
428	        _ => return Err(CompileError::BadGoal),
429	    };
430	    let pname = *atoms.name(fid).ok_or(CompileError::UnknownAtom)?;
431	    push_i(out, Instr::Call { label: lbl_entry(&pname)? })?;
432	    push_i(out, Instr::Halt)
433	}
434	
435	fn lbl_query() -> Result<LabelId, CompileError> {
436	    mk_label_str("query")
437	}
438	
439	fn mk_label_str(s: &str) -> Result<LabelId, CompileError> {
440	    BoundedStr::<LABEL_CAP>::from_str(s).map_err(|_| CompileError::LabelOverflow)
441	}
442	
443	fn lbl_entry(pname: &BoundedStr<NAME_CAP>) -> Result<LabelId, CompileError> {
444	    build_label(&[pname.as_str(), "_entry"])
445	}
446	
447	fn lbl_clause(pname: &BoundedStr<NAME_CAP>, k: u8) -> Result<LabelId, CompileError> {
448	    let mut dbuf = [0u8; 4];
449	    let ks = u8_to_decimal(k, &mut dbuf);
450	    build_label(&[pname.as_str(), "_c", ks])
451	}
452	
453	fn lbl_clause_body(pname: &BoundedStr<NAME_CAP>, k: u8) -> Result<LabelId, CompileError> {
454	    let mut dbuf = [0u8; 4];
455	    let ks = u8_to_decimal(k, &mut dbuf);
456	    build_label(&[pname.as_str(), "_c", ks, "_body"])
457	}
458	
459	fn build_label(parts: &[&str]) -> Result<LabelId, CompileError> {
460	    let total: usize = parts.iter().map(|s| s.len()).sum();
461	    if total > LABEL_CAP {
462	        return Err(CompileError::LabelOverflow);
463	    }
464	    let mut buf = [0u8; LABEL_CAP];
465	    let mut pos = 0;
466	    for part in parts {
467	        let b = part.as_bytes();
468	        buf[pos..pos + b.len()].copy_from_slice(b);
469	        pos += b.len();
470	    }
471	    let s = core::str::from_utf8(&buf[..pos]).expect("ascii label parts");
472	    BoundedStr::<LABEL_CAP>::from_str(s).map_err(|_| CompileError::LabelOverflow)
473	}
474	
475	fn u8_to_decimal(n: u8, buf: &mut [u8; 4]) -> &str {
476	    if n == 0 {
477	        buf[0] = b'0';
478	        return core::str::from_utf8(&buf[..1]).expect("ascii zero");
479	    }
480	    let mut tmp: [u8; 3] = [0; 3];
481	    let mut n32 = n as u32;
482	    let mut i = 0usize;
483	    while n32 > 0 {
484	        tmp[i] = b'0' + (n32 % 10) as u8;
485	        n32 /= 10;
486	        i += 1;
487	    }
488	    for j in 0..i {
489	        buf[j] = tmp[i - 1 - j];
490	    }
491	    core::str::from_utf8(&buf[..i]).expect("ascii digits")
492	}
