494	#[cfg(test)]
495	mod tests {
496	    use super::*;
497	    use crate::parse::parse;
498	    use crate::tokenize::tokenize;
499	
500	    fn compile_src(src: &str) -> BoundedArr<Instr, MAX_INSTR> {
501	        let toks = tokenize(src).expect("tokenize ok");
502	        let mut atoms = AtomTable::new();
503	        let clauses = parse(&toks, &mut atoms).expect("parse ok");
504	        compile(&clauses, &atoms).expect("compile ok")
505	    }
506	
507	    fn atom_id(atoms: &AtomTable, name: &str) -> AtomId {
508	        for i in 0..atoms.len() as AtomId {
509	            if atoms.name(i).expect("id in range").as_str() == name {
510	                return i;
511	            }
512	        }
513	        panic!("atom {name:?} not interned");
514	    }
515	
516	    fn as_label(i: &Instr) -> Option<&str> {
517	        match i {
518	            Instr::Label(l) => Some(l.as_str()),
519	            _ => None,
520	        }
521	    }
522	
523	    /// Pinned reference for examples/ancestor.pl. Corresponds to:
524	    ///   5 atom dirs + 1 `Execute query` + 14 instrs for parent group
525	    ///   + 21 instrs for ancestor group + 5 instrs for query = 46.
526	    /// Derived by hand-tracing the codegen.sno algorithm; consistent
527	    /// with a codegen.sno run modulo the atom-dir subset we intern
528	    /// versus codegen.sno's hardcoded 10-atom preamble.
529	    const ANCESTOR_INSTR_COUNT: usize = 46;
530	
531	    #[test]
532	    fn compile_ancestor_instruction_count() {
533	        let src = include_str!("../examples/ancestor.pl");
534	        let prog = compile_src(src);
535	        assert_eq!(prog.len(), ANCESTOR_INSTR_COUNT);
536	    }
537	
538	    #[test]
539	    fn compile_ancestor_first_and_last_instructions() {
540	        let src = include_str!("../examples/ancestor.pl");
541	        let prog = compile_src(src);
542	        // First instructions are all AtomDirs.
543	        match prog.get(0).expect("first") {
544	            Instr::AtomDir { id, .. } => assert_eq!(*id, 0),
545	            other => panic!("expected AtomDir, got {other:?}"),
546	        }
547	        // Last instruction is Halt (end of query).
548	        assert!(matches!(prog.get(prog.len() - 1), Some(Instr::Halt)));
549	    }
550	
551	    #[test]
552	    fn compile_ancestor_has_expected_labels() {
553	        let src = include_str!("../examples/ancestor.pl");
554	        let prog = compile_src(src);
555	        let labels: Vec<&str> = prog.iter().filter_map(as_label).collect();
556	        assert_eq!(
557	            labels,
558	            vec![
559	                "parent_c1_body",
560	                "parent_c2_body",
561	                "parent_entry",
562	                "parent_c2",
563	                "ancestor_c1_body",
564	                "ancestor_c2_body",
565	                "ancestor_entry",
566	                "ancestor_c2",
567	                "query",
568	            ]
569	        );
570	    }
